code.C:
#include <stdio.h>
int main() {
    int k, n, w;
    scanf("%d %d %d", &k, &n, &w);
    int total = (w * (w + 1)) / 2 * k;
    if (total <= n) printf("%d\n", 0);
    else printf("%d\n", total - n);
    return 0;
}

